@app.route("/analytics/recent", methods=["GET"])
def recent_activity():
    days = int(request.args.get("days", 30))
    cutoff = datetime.utcnow().timestamp() - (days * 86400)
    cutoff_dt = datetime.utcfromtimestamp(cutoff)

    try:
        pipeline = [
            {"$match": {"created_at": {"$gte": cutoff_dt}}},
            {
                "$group": {
                    "_id": {
                        "year": {"$year": "$created_at"},
                        "month": {"$month": "$created_at"},
                        "day": {"$dayOfMonth": "$created_at"}
                    },
                    "documents_created": {"$sum": 1}
                }
            },
            {
                "$project": {
                    "_id": 0,
                    "year": "$_id.year",
                    "month": "$_id.month",
                    "day": "$_id.day",
                    "documents_created": 1
                }
            },
            {"$sort": {"year": 1, "month": 1, "day": 1}}
        ]
        result = list(documents.aggregate(pipeline))
        return jsonify(serialize_doc(result))
    except PyMongoError as e:
        return json_error(str(e), 500)

